// src/utils/emailService.js
// Consolidated email service - all email functions in one place
// Generated by Phase 2 refactoring (2026-03-31)

import emailjs from "emailjs-com";
import { sendEmailApi } from "./hooks/api/emailApi";
import { requestEmailTemplates } from "./constants/requestEmailTemplates";

// ============================================================
// Configuration
// ============================================================
const EMAILJS_USER_ID = "xlmGc2aT4GDUYDQWT";
const EMAILJS_SERVICE_ID = "service_wka3qqh";

// Initialize once
emailjs.init(EMAILJS_USER_ID);

// ============================================================
// Core send function - all others delegate to this
// ============================================================
export async function sendEmail(templateId, templateParams, onSuccess = null, onError = null) {
  return emailjs
    .send(EMAILJS_SERVICE_ID, templateId, templateParams)
    .then((response) => {
      if (typeof onSuccess === "function") onSuccess(response);
      return response;
    })
    .catch((err) => {
      console.error("Failed to send email:", err);
      if (typeof onError === "function") onError(err);
      throw err;
    });
}

