export async function sendWelcomeEmail(
  templateParams,
  emailPayload,
  onSuccess = null,
  onError = null
) {
  const emailBody = `<html>
    <body>
      <div style="font-family: Arial, sans-serif; background-color: #f4f4f4; color: #333; padding: 20px;">
          <div style="background-color: #ffffff; border-radius: 8px; padding: 30px; max-width: 600px; margin: 0 auto; box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);">
              <!-- English Version -->
              <div style="text-align: center; color: #2c3e50;">
                  <h2>Welcome to MRNA - ${emailPayload.name}</h2>
              </div>
          </div>
      </div>
    </body>
  </html>`;

  const payload = {
    subject: templateParams.subject || "Welcome to MRNA",
    html_body: emailBody,
    email: emailPayload.email,
  };

  try {
    const res = await sendEmailApi(payload);
    if (typeof onSuccess === "function") onSuccess(res);
    return res;
  } catch (err) {
    if (typeof onError === "function") onError(err);
    throw err;
  }
}

