/**
 * -------------------
 * Interview Emails (first, second, third, interviewer)
 * -------------------
 */
export const sendFirstInterviewEmail = async ({
  candidate_name,
  interview_date,
  interview_time,
  email,
  interviewTypeField,
  interviewUrlField,
  interviewLocationField,
  onSuccess = null,
  onError = null,
}) => {
  let emailBody = "";
  let subject =
    "First Interview Invitation – MRNA | دعوة للمقابلة الأولى – MRNA";

  // Normalize type to lowercase for safe matching
  const interviewType = interviewTypeField?.toLowerCase() || "";
  
  if (interviewType.includes("online")) {
    // ✅ Online template
    emailBody = `
      <html>
        <body style="font-family: Arial, sans-serif; color: #333; line-height:1.6;">
          <!-- Arabic Version -->
          <p>عزيزنا المرشح،</p>
          <p>نتواصل معك نحن إدارة توظيف شركة مرنة للتمويل لإجراء مقابلة عن بعد يوم (${interview_time}) الموافق ${interview_date}.</p>
          <p><strong>رابط المقابلة:</strong> ${interviewUrlField || "N/A"}</p>
          <p>مع الشكر.</p>

          <hr style="margin:20px 0;" />

          <!-- English Version -->
          <p>Dear Candidate,</p>
          <p>We are contacting you from the Recruitment Department at Marna Financing Company to conduct a virtual interview on <strong>${interview_time}</strong> corresponding to <strong>${interview_date}</strong>.</p>
          <p><strong>Interview Link:</strong> ${interviewUrlField || "N/A"}</p>
          <p>Thank you.</p>
        </body>
      </html>
    `;
  } else if (interviewType.includes("physical")) {
    // ✅ Physical template
    emailBody = `
      <html>
        <body style="font-family: Arial, sans-serif; color: #333; line-height:1.6;">
          <!-- Arabic Version -->
          <p>عزيزنا المرشح،</p>
          <p>نتواصل معك نحن إدارة توظيف شركة مرنة للتمويل لإجراء مقابلة حضورية يوم (${interview_time}) الموافق ${interview_date}.</p>
          <p><strong>موقع المقابلة:</strong> ${
            interviewLocationField || "N/A"
          }</p>
          <p>نأمل احضار السيرة الذاتية المحدثة.</p>
          <p>مع الشكر.</p>

          <hr style="margin:20px 0;" />

          <!-- English Version -->
          <p>Dear Candidate,</p>
          <p>We are contacting you from the Recruitment Department at Marna Financing Company to invite you for an in-person interview on <strong>${interview_time}</strong> corresponding to <strong>${interview_date}</strong>.</p>
          <p><strong>Interview Location:</strong> ${
            interviewLocationField || "N/A"
          }</p>
          <p>Please bring your updated resume with you.</p>
          <p>Thank you.</p>
        </body>
      </html>
    `;
  } else {
    // ✅ Fallback generic template
    emailBody = `
        <html>
        <body style="font-family: Arial, sans-serif; color: #333; line-height:1.6;">
          <!-- Arabic Version -->
          <p>عزيزنا المرشح،</p>
          <p>نتواصل معك نحن إدارة توظيف شركة مرنة للتمويل لإجراء مقابلة حضورية يوم (${interview_time}) الموافق ${interview_date}.</p>
          <p>نأمل احضار السيرة الذاتية المحدثة.</p>
          <p>مع الشكر.</p>

          <hr style="margin:20px 0;" />

          <!-- English Version -->
          <p>Dear Candidate,</p>
          <p>We are contacting you from the Recruitment Department at Marna Financing Company to invite you for an in-person interview on <strong>${interview_time}</strong> corresponding to <strong>${interview_date}</strong>.</p>
          <p>Please bring your updated resume with you.</p>
          <p>Thank you.</p>
        </body>
      </html>
    `;
  }

  const payload = {
    subject,
    html_body: emailBody,
    email,
  };

  try {
    const response = await sendEmailApi(payload);
    if (typeof onSuccess === "function") onSuccess(response);
    return response;
  } catch (err) {
    console.error("❌ Failed to send first interview email:", err);
    if (typeof onError === "function") onError(err);
    throw err;
  }
};

