export const approvalEmailSender = async ({
  email,
  approvalPayload,
  approvalType,
  approverName,
  approverRole,
  onSuccess = null,
  onError = null,
}) => {
  // Normalize role name
  let userRole =
    approverRole === "hr_manager"
      ? "HR Manager"
      : approverRole === "hr"
      ? "HR"
      : approverRole === "hod"
      ? "HOD"
      : approverRole === "manager"
      ? "Manager"
      : approverRole;

  // Default content & subject
  let content = `Your ${approvalType.replace(/_/g, " ")} has been approved by ${userRole}, ${approverName}.`;
  let emailSubject = `Approval Notification - ${approvalType.replace(/_/g, " ")}`;

  // ✅ Special case: pay_stopage
  if (approvalType === "pay_stopage") {
    content = `Your pay stoppage request has been approved by ${userRole}, ${approverName}. Salary processing will reflect this update.`;
    emailSubject = `Approval Notification - Pay Stoppage`;
  }
   else if (approvalType === "leave_requests") {
    content = `Your ${approvalPayload?.leave_type} has been approved by ${approverName} ${approverRole}`;
    emailSubject = `Approval for the ${approvalPayload?.leave_type}`;
  } else if (approvalType === "allowance_requests") {
    content = `Your ticket request for amount ${approvalPayload?.amount} which was requested on the date ${approvalPayload?.requested_date} has been approved by the ${userRole}, ${approverName}`;
    emailSubject = `Approval for the Allowance Request`;
  }
  // ✅ Special case: resignation_request
  else if (approvalType === "resignation_request") {
    content = `Your resignation request has been approved by ${userRole}, ${approverName}. Kindly follow up with HR for the clearance and exit process.`;
    emailSubject = `Approval Notification - Resignation Request`;
  }
  // ✅ Generic case (all others)
  else {
    content = `Your ${approvalType.replace(/_/g, " ")} has been approved by ${userRole}, ${approverName}.`;
    emailSubject = `Approval Notification - ${approvalType.replace(/_/g, " ")}`;
  }

  // ✅ Single HTML template
  const emailBody = `
  <!DOCTYPE html>
  <html>
  <head>
    <style>
      body {
        font-family: Arial, sans-serif;
        background-color: #f4f4f4;
        color: #333;
        padding: 20px;
      }
      .container {
        background-color: #ffffff;
        border-radius: 8px;
        padding: 30px;
        max-width: 600px;
        margin: 0 auto;
        box-shadow: 0 4px 10px rgba(0,0,0,0.1);
      }
      .header {
        text-align: center;
        color: #2c3e50;
        font-size: 20px;
        margin-bottom: 20px;
      }
      .content {
        font-size: 15px;
        line-height: 1.5;
      }
      .footer {
        text-align: center;
        font-size: 12px;
        color: #777;
        margin-top: 30px;
      }
    </style>
  </head>
  <body>
    <div class="container">
      <div class="header">Approval Notification</div>
      <div class="content">
        <p>${content}</p>
      </div>
      <div class="footer">
        <p>This is an automated message. Please do not reply.</p>
      </div>
    </div>
  </body>
  </html>
  `;

  const payload = {
    subject: emailSubject,
    html_body: emailBody,
    email,
    // email: "zeeshanmrna@yopmail.com"
  };

  return sendEmailApi(payload)
    .then((res) => {
      onSuccess?.(res);
      return res;
    })
    .catch((err) => {
      onError?.(err);
      throw err;
    });
};

export const rejectionEmailSender = async ({
  email,
  rejectPayload,
  rejectionType,
  rejectorName,
  reason,
  rejectorRole,
  onSuccess = null,
  onError = null,
}) => {
  // Normalize role name
  let userRole =
    rejectorRole === "hr_manager"
      ? "HR Manager"
      : rejectorRole === "hr"
      ? "HR"
      : rejectorRole === "hod"
      ? "HOD"
      : rejectorRole === "manager"
      ? "Manager"
      : rejectorRole;

  // Default content & subject
  let content = `Your ${rejectionType.replace(/_/g, " ")} has been rejected by ${userRole}, ${rejectorName}${
    reason ? ` for the reason: ${reason}` : ""
  }.`;
  let emailSubject = `Rejection Notification - ${rejectionType.replace(/_/g, " ")}`;

  // ✅ Special case: pay_stopage
  if (rejectionType === "pay_stopage") {
    content = `Your pay stoppage request has been rejected by ${userRole}, ${rejectorName}${
      reason ? ` for the reason: ${reason}` : ""
    }. Please contact HR/Finance for clarification.`;
    emailSubject = `Rejection Notification - Pay Stoppage`;
  }
  // ✅ Special case: resignation_request
  else if (rejectionType === "resignation_request") {
    content = `Your resignation request has been rejected by ${userRole}, ${rejectorName}${
      reason ? ` for the reason: ${reason}` : ""
    }. Kindly follow up with HR for further details.`;
    emailSubject = `Rejection Notification - Resignation Request`;
  }
    else if (rejectionType === "leave_requests") {
    content = `Your ${rejectPayload?.leave_type} has been rejected by ${rejectorName} ${rejectorRole} for the reason: ${reason}`;
    emailSubject = `Rejection for the ${rejectPayload?.leave_type}`;
  } else if (rejectionType === "allowance_requests") {
    content = `Your ticket request for amount ${rejectPayload?.amount} which was requested on the date ${rejectPayload?.requested_date} has been Rejected by the ${userRole}, ${rejectorName} due to the reason: ${reason}`;
    emailSubject = `Rejection for the Allowance Request`;
  }
  // ✅ Generic fallback (all others)
  else {
    content = `Your ${rejectionType.replace(/_/g, " ")} has been rejected by ${userRole}, ${rejectorName}${
      reason ? ` for the reason: ${reason}` : ""
    }.`;
    emailSubject = `Rejection Notification - ${rejectionType.replace(/_/g, " ")}`;
  }

  // ✅ Single HTML template
  const emailBody = `
  <!DOCTYPE html>
  <html>
  <head>
    <style>
      body {
        font-family: Arial, sans-serif;
        background-color: #f4f4f4;
        color: #333;
        padding: 20px;
      }
      .container {
        background-color: #ffffff;
        border-radius: 8px;
        padding: 30px;
        max-width: 600px;
        margin: 0 auto;
        box-shadow: 0 4px 10px rgba(0,0,0,0.1);
      }
      .header {
        text-align: center;
        color: #c0392b;
        font-size: 20px;
        margin-bottom: 20px;
      }
      .content {
        font-size: 15px;
        line-height: 1.5;
      }
      .footer {
        text-align: center;
        font-size: 12px;
        color: #777;
        margin-top: 30px;
      }
    </style>
  </head>
  <body>
    <div class="container">
      <div class="header">Rejection Notification</div>
      <div class="content">
        <p>${content}</p>
      </div>
      <div class="footer">
        <p>This is an automated message. Please do not reply.</p>
      </div>
    </div>
  </body>
  </html>
  `;

  const payload = {
    subject: emailSubject,
    html_body: emailBody,
    email,
    // email: "zeeshanmrna@yopmail.com"
  };

  return sendEmailApi(payload)
    .then((res) => {
      onSuccess?.(res);
      return res;
    })
    .catch((err) => {
      onError?.(err);
      throw err;
    });
};



