export const transactionApprovalEmailSenderToFinance = async (
  email,
  approvalPayload,
  approvalType,
  approverName,
  approverRole,
  onSuccess = null,
  onError = null
) => {
  const emailSubject = `Allowance Request Approved`;

  let userRole =
    approverRole === "hr_manager"
      ? "HR Manager"
      : approverRole === "hr"
      ? "HR"
      : approverRole === "manager"
      ? "Manager"
      : approverRole;

  const emailBody = `
  <!DOCTYPE html>
  <html>
  <head>
    <style>
      body {
        font-family: Arial, sans-serif;
        background-color: #f4f4f4;
        color: #333;
        padding: 20px;
      }
      .container {
        background-color: #ffffff;
        border-radius: 8px;
        padding: 30px;
        max-width: 600px;
        margin: 0 auto;
        box-shadow: 0 4px 10px rgba(0,0,0,0.1);
      }
      .header {
        text-align: center;
        color: #2c3e50;
        margin-bottom: 20px;
      }
      .footer {
        text-align: center;
        font-size: 12px;
        color: #777;
        margin-top: 30px;
      }
    </style>
  </head>
  <body>
      <p>Dear Finance Manager,</p>

      <p>I hope this email finds you well.</p>

      <p>
        Please be informed that the <strong>allowance request</strong> has been
        <strong>approved by the ${userRole} ${approverName}</strong> of amount <strong>${approvalPayload?.amount}</strong> requested on ${approvalPayload?.requested_date} and is now ready for
        processing by the Finance Department.
      </p>

      <div class="footer">
        <p>This is an automated message. Please do not reply.</p>
      </div>
    </div>
  </body>
  </html>
  `;

  const payload = {
    subject: emailSubject,
    html_body: emailBody,
    email: email,
  };

  return sendEmailApi(payload)
    .then((res) => {
      if (onSuccess) onSuccess(res);
      return res;
    })
    .catch((err) => {
      if (onError) onError(err);
      throw err;
    });
};
